package tests.panels.arming;

import base.TestBase;
import org.testng.annotations.Test;

// EX-T1001
public class ArmAwayGroupTest extends TestBase {

    @Test(groups = {"arm-away", "group-01"})
    public void testArmAwayFromKeypad() {
        // Step 1: Verify panel is in DISARMED state with no active alarms
        REPORT("Panel is in DISARMED state");
        panel.assertState(PanelState.DISARMED);

        REPORT("No active alarms on panel");
        alarmManager.assertNoActiveAlarms();

        // Step 2: Enter master code and initiate ARM AWAY
        REPORT("Master code entered at keypad");
        keypad.enterCode(config.getMasterCode());

        REPORT("ARM AWAY sequence initiated");
        keypad.pressArmAway();

        // Step 3: Exit delay countdown begins
        REPORT("Exit delay countdown is visible");
        panel.assertExitDelayActive();
        panel.waitForExitDelay(config.getExitDelaySeconds());

        // Step 4: Panel transitions to ARMED AWAY, all sensors active
        REPORT("Panel transitions to ARMED AWAY");
        panel.assertState(PanelState.ARMED_AWAY);

        REPORT("All motion sensors are active");
        sensorManager.assertAllActive(SensorType.MOTION);

        // Cleanup: disarm
        panel.disarm(config.getMasterCode());
    }
}
